import { useState, useEffect } from "react";
import axios from "axios";

const API = "";

const STATS = [
  { value: "1,247", label: "URLs Scanned" },
  { value: "983", label: "Threats Blocked" },
  { value: "298,450", label: "Indians Protected" },
  { value: "95", label: "Engines Active" },
];

export default function App() {
  const [url, setUrl] = useState("");
  const [message, setMessage] = useState("");
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [recentScans, setRecentScans] = useState([]);

  useEffect(() => { fetchRecent(); }, []);

  const fetchRecent = async () => {
    try {
      const res = await axios.get(`${API}/recent-scans`);
      setRecentScans((res.data.scans || []).filter(s => s.url && s.url !== "string"));
    } catch (e) {}
  };

  const scan = async () => {
    if (!url) return;
    setLoading(true);
    setResult(null);
    try {
      const res = await axios.post(`${API}/scan`, { url, message });
      setResult(res.data);
      fetchRecent();
    } catch (e) { alert("Backend not running!"); }
    setLoading(false);
  };

  const getColor = (score) => {
    if (score >= 75) return "#ff2d2d";
    if (score >= 50) return "#ff8800";
    if (score >= 30) return "#ffcc00";
    return "#00c853";
  };

  const getLevel = (score) => {
    if (score >= 75) return "CRITICAL";
    if (score >= 50) return "HIGH";
    if (score >= 30) return "MEDIUM";
    return "SAFE";
  };

  const signals = result?.signals ? [
    { name: "AI Analysis", score: result.signals.ai_analysis?.ai_score || 0, max: 100, icon: "🧠", desc: result.signals.ai_analysis?.explanation || "" },
    { name: "Ghost Sandbox", score: result.signals.sandbox?.score || 0, max: 25, icon: "👻", desc: result.signals.sandbox?.verdict || "" },
    { name: "Click Velocity", score: result.signals.click_velocity?.score || 0, max: 20, icon: "⚡", desc: result.signals.click_velocity?.verdict || "" },
    { name: "Geo Velocity", score: result.signals.geo_velocity?.score || 0, max: 15, icon: "🌍", desc: result.signals.geo_velocity?.verdict || "" },
    { name: "Dwell Time", score: result.signals.dwell_time?.score || 0, max: 10, icon: "⏱️", desc: result.signals.dwell_time?.verdict || "" },
  ] : [];

  return (
    <div style={{ background: "#060608", minHeight: "100vh", color: "#fff", fontFamily: "'Courier New', monospace", padding: "0" }}>

      {/* Header */}
      <div style={{ background: "#080810", borderBottom: "1px solid #7F77DD33", padding: "20px 32px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "14px" }}>
          <div style={{ fontSize: "32px" }}>🛡️</div>
          <div>
            <div style={{ fontSize: "20px", fontWeight: "700", color: "#7F77DD", letterSpacing: "3px" }}>ShieldNetX</div>
            <div style={{ fontSize: "10px", color: "#444", letterSpacing: "2px" }}>CYBER THREAT INTELLIGENCE PLATFORM</div>
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: "8px", fontSize: "10px", color: "#555", letterSpacing: "1px" }}>
          <div style={{ width: "6px", height: "6px", background: "#00c853", borderRadius: "50%", boxShadow: "0 0 6px #00c853" }}></div>
          ALL SYSTEMS OPERATIONAL
        </div>
      </div>

      {/* Stats */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: "1px", background: "#7F77DD22", borderBottom: "1px solid #7F77DD22" }}>
        {STATS.map((s, i) => (
          <div key={i} style={{ background: "#060608", padding: "20px 24px" }}>
            <div style={{ fontSize: "28px", fontWeight: "700", color: "#7F77DD" }}>{s.value}</div>
            <div style={{ fontSize: "9px", color: "#444", letterSpacing: "2px", marginTop: "4px", textTransform: "uppercase" }}>{s.label}</div>
          </div>
        ))}
      </div>

      <div style={{ padding: "24px 32px", maxWidth: "900px", margin: "0 auto" }}>

        {/* Scan box */}
        <div style={{ background: "#080810", border: "1px solid #111118", borderRadius: "8px", padding: "24px", marginBottom: "20px" }}>
          <div style={{ fontSize: "9px", color: "#7F77DD", letterSpacing: "3px", marginBottom: "16px", textTransform: "uppercase" }}>// Threat Scanner</div>
          <input
            value={url}
            onChange={e => setUrl(e.target.value)}
            onKeyDown={e => e.key === "Enter" && scan()}
            placeholder="Paste suspicious URL here..."
            style={{ width: "100%", padding: "12px 16px", background: "#060608", border: "1px solid #111118", borderRadius: "6px", color: "#ccc", fontSize: "13px", marginBottom: "10px", outline: "none", fontFamily: "'Courier New', monospace", boxSizing: "border-box" }}
          />
          <textarea
            value={message}
            onChange={e => setMessage(e.target.value)}
            placeholder="Paste the full WhatsApp/SMS message (optional — improves accuracy)..."
            rows={2}
            style={{ width: "100%", padding: "12px 16px", background: "#060608", border: "1px solid #111118", borderRadius: "6px", color: "#ccc", fontSize: "13px", marginBottom: "14px", outline: "none", fontFamily: "'Courier New', monospace", resize: "none", boxSizing: "border-box" }}
          />
          <button
            onClick={scan}
            disabled={loading}
            style={{ width: "100%", padding: "14px", background: loading ? "#111" : "linear-gradient(135deg, #7F77DD, #534AB7)", color: "#fff", border: "none", borderRadius: "6px", fontSize: "14px", fontWeight: "700", cursor: loading ? "not-allowed" : "pointer", letterSpacing: "2px", fontFamily: "'Courier New', monospace" }}>
            {loading ? "[ SCANNING... ]" : "[ SCAN NOW ]"}
          </button>
        </div>

        {/* Results */}
        {result && (
          <div style={{ marginBottom: "20px" }}>
            {/* Score */}
            <div style={{ background: "#080810", border: `1px solid ${getColor(result.threat_score)}44`, borderLeft: `3px solid ${getColor(result.threat_score)}`, borderRadius: "8px", padding: "24px", marginBottom: "12px", textAlign: "center" }}>
              <div style={{ fontSize: "72px", fontWeight: "700", color: getColor(result.threat_score), lineHeight: "1" }}>{result.threat_score}</div>
              <div style={{ fontSize: "9px", color: "#444", letterSpacing: "3px", margin: "8px 0 14px", textTransform: "uppercase" }}>Threat Score out of 100</div>
              <div style={{ display: "inline-block", background: getColor(result.threat_score), color: "white", padding: "6px 24px", borderRadius: "3px", fontWeight: "700", fontSize: "12px", letterSpacing: "3px" }}>{result.threat_level}</div>
              <p style={{ color: "#555", marginTop: "14px", fontSize: "12px", letterSpacing: "1px" }}>{result.explanation}</p>
              {result.tamil_explanation && <p style={{ color: "#444", fontSize: "11px", marginTop: "6px" }}>{result.tamil_explanation}</p>}
            </div>

            {/* Signals */}
            <div style={{ background: "#080810", border: "1px solid #111118", borderRadius: "8px", padding: "20px", marginBottom: "12px" }}>
              <div style={{ fontSize: "9px", color: "#7F77DD", letterSpacing: "3px", marginBottom: "16px", textTransform: "uppercase" }}>// Signal Breakdown</div>
              {signals.map((sig, i) => (
                <div key={i} style={{ marginBottom: "14px" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "5px", fontSize: "12px" }}>
                    <span style={{ color: "#888" }}>{sig.icon} {sig.name}</span>
                    <span style={{ color: getColor((sig.score / sig.max) * 100), fontFamily: "'Courier New', monospace" }}>{sig.score}/{sig.max}</span>
                  </div>
                  <div style={{ background: "#060608", borderRadius: "2px", height: "4px" }}>
                    <div style={{ width: `${Math.min((sig.score / sig.max) * 100, 100)}%`, background: getColor((sig.score / sig.max) * 100), height: "4px", borderRadius: "2px", transition: "width 0.6s ease" }} />
                  </div>
                  <div style={{ fontSize: "10px", color: "#333", marginTop: "3px", letterSpacing: "1px" }}>{sig.desc}</div>
                </div>
              ))}
            </div>

            {/* Screenshot */}
            {result.screenshot_b64 && (
              <div style={{ background: "#080810", border: "1px solid #111118", borderRadius: "8px", padding: "20px", marginBottom: "12px" }}>
                <div style={{ fontSize: "9px", color: "#7F77DD", letterSpacing: "3px", marginBottom: "12px", textTransform: "uppercase" }}>// Ghost Sandbox Screenshot</div>
                <div style={{ fontSize: "10px", color: "#333", marginBottom: "10px", letterSpacing: "1px" }}>Malicious page captured safely — you never visited it</div>
                <img src={`data:image/png;base64,${result.screenshot_b64}`} alt="Sandbox" style={{ width: "100%", borderRadius: "4px", border: "1px solid #ff2d2d33" }} />
              </div>
            )}
          </div>
        )}

        {/* Recent Scans */}
        <div style={{ background: "#080810", border: "1px solid #111118", borderRadius: "8px", padding: "20px" }}>
          <div style={{ fontSize: "9px", color: "#7F77DD", letterSpacing: "3px", marginBottom: "16px", textTransform: "uppercase" }}>// Recent Threat Intelligence</div>
          {recentScans.length === 0 ? (
            <div style={{ textAlign: "center", color: "#333", padding: "20px", fontSize: "11px", letterSpacing: "2px" }}>NO SCANS YET</div>
          ) : (
            recentScans.map((scan, i) => (
              <div key={i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "10px 0", borderBottom: "1px solid #0d0d14", fontSize: "11px" }}>
                <span style={{ color: "#555", maxWidth: "55%", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", fontFamily: "'Courier New', monospace" }}>{scan.url}</span>
                <span style={{ color: getColor(scan.score), fontWeight: "700", fontFamily: "'Courier New', monospace" }}>{scan.score}/100</span>
                <span style={{ color: "#333", fontSize: "10px", letterSpacing: "1px" }}>{scan.scanned_at?.slice(11, 16)}</span>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}
